mapper.select:
SELECT o.*, s.name AS student_name, CASE WHEN o.order_type = 'COURSE' THEN c.name WHEN o.order_type = 'ACTIVITY' THEN COALESCE(NULLIF(TRIM(a.title), ''), a.name) ELSE p.name END AS product_name FROM order_info o LEFT JOIN sys_user s ON o.student_id = s.id LEFT JOIN product p ON o.order_type NOT IN ('COURSE', 'ACTIVITY') AND o.product_id = p.id LEFT JOIN course c ON o.order_type = 'COURSE' AND o.product_id = c.id LEFT JOIN activity a ON o.order_type = 'ACTIVITY' AND o.product_id = a.id
AND o.student_id = #{param.studentId} AND o.order_type = #{param.orderType} AND o.status = #{param.status}
ORDER BY COALESCE(o.complete_time, o.pay_time, o.create_time) DESC
